/* ── Founding spots polling ── */
function useFoundingSpots() {
  const [data, setData] = useState(null)
  useEffect(() => {
    const load = () =>
      fetch('/api/auth/founding-spots')
        .then(r => r.json())
        .then(d => setData(d))
        .catch(() => {})
    load()
    const id = setInterval(load, 30_000)
    return () => clearInterval(id)
  }, [])
  return data
}

